// Fold fcmp pred (fptrunc X), C into fcmp pred X, C' where C' is in X's type.
// This handles the case where we can combine a truncation and comparison.
static Instruction *foldFCmpFPTruncConst(FCmpInst &I, Instruction *LHSI,
                                         Constant *RHSC) {
  const APFloat *RHS;
  if (!match(RHSC, m_APFloat(RHS)))
    return nullptr;

  // Get the source type of the fptrunc (the wider type)
  Type *WideTy = LHSI->getOperand(0)->getType();
  Type *NarrowTy = LHSI->getType();

  // Only handle scalar types for now
  if (!WideTy->isFloatingPointTy() || !NarrowTy->isFloatingPointTy())
    return nullptr;

  const fltSemantics &WideSem = WideTy->getFltSemantics();
  const fltSemantics &NarrowSem = NarrowTy->getFltSemantics();

  FCmpInst::Predicate Pred = I.getPredicate();

  // For unordered predicates, we can't safely transform
  if (Pred == FCmpInst::FCMP_UNO || Pred == FCmpInst::FCMP_ORD)
    return nullptr;

  // Handle special cases: NaN, Infinity
  if (RHS->isNaN())
    return nullptr;

  if (RHS->isInfinity()) {
    // For infinity, the comparison semantics are preserved
    APFloat WideC = *RHS;
    bool Lossy;
    WideC.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy);
    Constant *NewC = ConstantFP::get(WideTy, WideC);
    return new FCmpInst(Pred, LHSI->getOperand(0), NewC, "", &I);
  }

  // Convert the constant to the wider type (this is exact for float values)
  APFloat WideC = *RHS;
  bool Lossy;
  WideC.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy);

  // For equality comparisons, we need to check if the conversion is exact
  // and handle the range of values that truncate to the same float
  if (I.isEquality()) {
    // For OEQ/UEQ: X == C (after trunc) means X is in [min_trunc_C, max_trunc_C]
    // For ONE/UNE: X != C (after trunc) means X is outside that range
    // This is complex, so for now we only handle the case where C is exactly
    // representable and there's no rounding ambiguity
    if (Lossy) {
      // The float constant cannot be exactly represented in the wider type
      // (this shouldn't happen for standard float->double)
      if (Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UEQ)
        return nullptr; // Can't simplify
      if (Pred == FCmpInst::FCMP_ONE || Pred == FCmpInst::FCMP_UNE)
        return nullptr; // Can't simplify
    }
    // For equality with exact representation, we can't directly transform
    // because multiple wide values truncate to the same narrow value
    return nullptr;
  }

  // For inequality comparisons, we need to find the boundary value
  // The key insight: for a float C, there's a range of doubles [D_min, D_max]
  // that truncate to C. We need to find D_min and D_max.

  // D_max is simply WideC (the exact conversion)
  // D_min is the smallest wide value that truncates to C

  // To find D_min:
  // 1. Find the previous float value (C_prev)
  // 2. The boundary between C_prev and C is approximately (C_prev + C) / 2
  // 3. D_min is the smallest wide value >= this boundary

  APFloat NarrowC = *RHS;

  // Find C_prev (previous float value)
  APFloat C_prev = NarrowC;
  bool Ignored;
  C_prev.next(/*nextDown=*/true);  // Go to previous float
  if (C_prev.category == APFloat::fcZero || C_prev.category == APFloat::fcInfinity) {
    // Hit zero or infinity, can't go further
    // Use the exact WideC as boundary
  }

  // Convert C_prev to wide type
  APFloat WideC_prev = C_prev;
  WideC_prev.convert(WideSem, APFloat::rmNearestTiesToEven, &Ignored);

  // The boundary is approximately the midpoint
  // For simplicity, we use: D_min = (WideC_prev + WideC) / 2
  // But we need to be careful about the exact boundary

  // Actually, a simpler approach: 
  // For >= and >: we want X >= D_min where D_min is the smallest wide that truncates to >= C
  // For <= and <: we want X <= D_max where D_max is the largest wide that truncates to <= C

  // D_max for C is WideC (exact conversion)
  // D_min for C: we need to find the smallest wide value that truncates to C

  // The algorithm: start from WideC and go down until truncation changes
  APFloat D_min = WideC;
  APFloat testVal = WideC;
  for (int i = 0; i < 100; ++i) {
    testVal.next(/*nextDown=*/true);
    APFloat testNarrow = testVal;
    testNarrow.convert(NarrowSem, APFloat::rmNearestTiesToEven, &Ignored);
    if (testNarrow != NarrowC) {
      // Went too far, back up
      D_min = testVal;
      D_min.next(/*nextDown=*/false);  // Go back up
      break;
    }
    D_min = testVal;
  }

  // Now D_min is the smallest wide value that truncates to C
  // D_max is WideC (the largest wide value that truncates to C)

  APFloat Boundary;
  switch (Pred) {
    case FCmpInst::FCMP_OGE:
    case FCmpInst::FCMP_UGE:
      // X >= C (after trunc) iff X >= D_min
      Boundary = D_min;
      break;
    case FCmpInst::FCMP_OLE:
    case FCmpInst::FCMP_ULE:
      // X <= C (after trunc) iff X <= D_max = WideC
      Boundary = WideC;
      break;
    case FCmpInst::FCMP_OGT:
    case FCmpInst::FCMP_UGT:
      // X > C (after trunc) iff X > D_max iff X >= next(D_max)
      Boundary = WideC;
      Boundary.next(/*nextDown=*/false);  // next up
      break;
    case FCmpInst::FCMP_OLT:
    case FCmpInst::FCMP_ULT:
      // X < C (after trunc) iff X < D_min iff X <= prev(D_min)
      Boundary = D_min;
      Boundary.next(/*nextDown=*/true);  // next down (prev)
      break;
    default:
      return nullptr;
  }

  Constant *NewC = ConstantFP::get(WideTy, Boundary);
  return new FCmpInst(Pred, LHSI->getOperand(0), NewC, "", &I);
}

