// Fold fcmp pred (fptrunc X), C into fcmp pred X, C' where C' is in X's type.
// This handles the case where we can combine a truncation and comparison.
static Instruction *foldFCmpFPTruncConst(FCmpInst &I, Instruction *LHSI,
                                         Constant *RHSC) {
  const APFloat *RHS;
  if (!match(RHSC, m_APFloat(RHS)))
    return nullptr;

  // Get the source type of the fptrunc (the wider type)
  Type *WideTy = LHSI->getOperand(0)->getType();
  Type *NarrowTy = LHSI->getType();

  // Only handle scalar IEEE floating point types for now
  if (!WideTy->isFloatingPointTy() || !NarrowTy->isFloatingPointTy())
    return nullptr;

  const fltSemantics &WideSem = WideTy->getFltSemantics();
  const fltSemantics &NarrowSem = NarrowTy->getFltSemantics();

  // Wide type must be larger than narrow type (check by mantissa width)
  int WideMantissa = WideTy->getFPMantissaWidth();
  int NarrowMantissa = NarrowTy->getFPMantissaWidth();
  if (WideMantissa <= 0 || NarrowMantissa <= 0 || WideMantissa <= NarrowMantissa)
    return nullptr;

  FCmpInst::Predicate Pred = I.getPredicate();

  // For unordered predicates, we can't safely transform
  if (Pred == FCmpInst::FCMP_UNO || Pred == FCmpInst::FCMP_ORD)
    return nullptr;

  // Handle special cases: NaN, Infinity
  if (RHS->isNaN())
    return nullptr;

  // Convert the constant to the wider type (this is exact for float values)
  APFloat WideC = *RHS;
  bool Lossy;
  WideC.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy);

  if (RHS->isInfinity()) {
    // For infinity, the comparison semantics are preserved
    Constant *NewC = ConstantFP::get(WideTy, WideC);
    return new FCmpInst(Pred, LHSI->getOperand(0), NewC, "", &I);
  }

  // For equality comparisons, we can't directly transform
  // because multiple wide values truncate to the same narrow value
  if (I.isEquality())
    return nullptr;

  // For inequality comparisons, we need to find the boundary value.
  // The key insight: for a float C, doubles in the range [midpoint_lower, midpoint_upper)
  // truncate to C, where:
  //   midpoint_lower = (prev_float(C) + C) / 2
  //   midpoint_upper = (C + next_float(C)) / 2

  // Find C_prev (previous float value)
  APFloat C_prev = *RHS;
  C_prev.next(/*nextDown=*/true);

  // Find C_next (next float value)  
  APFloat C_next = *RHS;
  C_next.next(/*nextDown=*/false);

  // Convert to wide type
  APFloat WideC_prev = C_prev;
  WideC_prev.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy);

  APFloat WideC_next = C_next;
  WideC_next.convert(WideSem, APFloat::rmNearestTiesToEven, &Lossy);

  // Compute midpoints: (WideC_prev + WideC) / 2 and (WideC + WideC_next) / 2
  // We need to do this carefully to avoid overflow/underflow

  APFloat MidpointLower = WideC_prev;
  MidpointLower.add(WideC, APFloat::rmNearestTiesToEven);
  APFloat two(WideSem, 2);
  MidpointLower.divide(two, APFloat::rmNearestTiesToEven);

  APFloat MidpointUpper = WideC;
  MidpointUpper.add(WideC_next, APFloat::rmNearestTiesToEven);
  MidpointUpper.divide(two, APFloat::rmNearestTiesToEven);

  // Now determine the boundary based on the predicate
  APFloat Boundary(WideSem);
  switch (Pred) {
    case FCmpInst::FCMP_OGE:
    case FCmpInst::FCMP_UGE:
      // (float)X >= C iff X >= MidpointLower
      Boundary = MidpointLower;
      break;
    case FCmpInst::FCMP_OLE:
    case FCmpInst::FCMP_ULE:
      // (float)X <= C iff X < MidpointUpper iff X <= prev(MidpointUpper)
      Boundary = MidpointUpper;
      Boundary.next(/*nextDown=*/true);
      break;
    case FCmpInst::FCMP_OGT:
    case FCmpInst::FCMP_UGT:
      // (float)X > C iff X >= MidpointUpper
      Boundary = MidpointUpper;
      break;
    case FCmpInst::FCMP_OLT:
    case FCmpInst::FCMP_ULT:
      // (float)X < C iff X < MidpointLower iff X <= prev(MidpointLower)
      Boundary = MidpointLower;
      Boundary.next(/*nextDown=*/true);
      break;
    default:
      return nullptr;
  }

  Constant *NewC = ConstantFP::get(WideTy, Boundary);
  return new FCmpInst(Pred, LHSI->getOperand(0), NewC, "", &I);
}
CODEEOF
